// Determine which posting day and post type rotation
const now = new Date();
const dateStr = now.toISOString().split('T')[0];

// Day name for context
const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const dayName = dayNames[now.getDay()];

// Post type rotation: Mon=insight, Wed=educational, Fri=engagement
// (cycles through the three types across posting days)
const postTypeByDay = {
  monday: 'insight',
  wednesday: 'educational',
  friday: 'engagement'
};
const todayPostType = postTypeByDay[dayName] || 'insight';

// Idempotency key prevents duplicate runs on same day
const idempotencyKey = `linkedin-post:${dateStr}`;

const prompt = `Generate LinkedIn post drafts for today's posting slot.

**Action**: linkedin-post
**Posting Day**: ${dayName.charAt(0).toUpperCase() + dayName.slice(1)}, ${dateStr}
**Primary Post Type**: ${todayPostType}

**Instructions**:
1. Read config.json at salesMarketing.linkedin for postTypes config, commentStyle brandVoice, and confluenceQueue paths
2. Read skills/certpilot-brand/SKILL.md and skills/certpilot-social/SKILL.md for brand voice
3. Search Confluence MKTG space for LI-POST pages created in the last 14 days to check what has been posted recently and avoid repeating topics
4. Generate 3 post options — one insight, one educational, one engagement — optimised for the UK defence/compliance audience
5. The PRIMARY post type today is "${todayPostType}" — lead with that option as Option 1
6. Store all 3 options in a Confluence page at MKTG/Social Media/LinkedIn Queue/Post Drafts
7. Page title: "LI-POST - ${dateStr} - 3 Options"
8. Apply labels: content-draft, linkedin-post
9. Each post must be 150-250 words, include 3-5 relevant hashtags, and follow the brand voice rules

The workflow will notify #marketing when the drafts are ready — you do NOT need to send a message.`;

return [{
  json: {
    dateStr,
    dayName,
    todayPostType,
    idempotencyKey,
    prompt
  }
}];
